func NewGateeu(userConfig map[string]any) *Gateeu {
   p := NewGateeuCore()
   p.Init(userConfig)
   return &Gateeu{
       GateeuCore: p,
       Core:  p,
       exchangeTyped: NewGateFromCore(&(p.GateCore)),
   }
}
func NewGateeuFromCore(core *GateCore) *Gate {
   return &Gate{
       GateCore: core,
       Core:  core,
       exchangeTyped: NewExchangeTyped(&core.Exchange),
   }
}

